import * as vscode from 'vscode'
import { setCompanionOpen, isCompanionOpen } from './host/extension-context'

/** Companion 双窗 — VS Code 侧栏拖拽或独立 Panel */
export const registerCompanionCommands = (context: vscode.ExtensionContext): void => {
  context.subscriptions.push(
    vscode.commands.registerCommand('axecoder.toggleCompanion', async () => {
      if (isCompanionOpen()) {
        await vscode.commands.executeCommand('workbench.action.moveViewToPrimarySideBar')
        setCompanionOpen(false)
      } else {
        await vscode.commands.executeCommand('workbench.action.moveViewToSecondarySideBar')
        setCompanionOpen(true)
      }
      await vscode.commands.executeCommand('axecoder.chat.focus')
    }),
  )
}
