/**
 * AxeCoder 宿主抽象 — VS Code Extension / Electron 注入实现
 */
export interface AxecoderFsReadResult {
  ok: boolean
  content?: string
  error?: string
}

export interface AxecoderFsWriteResult {
  ok: boolean
  error?: string
}

export interface AxecoderFsStat {
  isFile: boolean
  isDirectory: boolean
  size: number
  mtimeMs: number
}

export interface AxecoderFsHost {
  readFile(filePath: string, encoding?: 'utf8'): Promise<AxecoderFsReadResult>
  writeFile(filePath: string, content: string): Promise<AxecoderFsWriteResult>
  stat(filePath: string): Promise<AxecoderFsStat | null>
  exists(filePath: string): Promise<boolean>
}

export interface AxecoderShellHost {
  exec(command: string, cwd: string): Promise<{ stdout: string; stderr: string; exitCode: number }>
}

export interface AxecoderSecretsHost {
  get(key: string): Promise<string | undefined>
  set(key: string, value: string): Promise<void>
  delete(key: string): Promise<void>
}

export interface AxecoderWindowHost {
  showInformationMessage(message: string): Promise<void>
  showErrorMessage(message: string): Promise<void>
  showWarningMessage(message: string): Promise<void>
}

export interface AxecoderHost {
  fs: AxecoderFsHost
  shell: AxecoderShellHost
  secrets: AxecoderSecretsHost
  window: AxecoderWindowHost
  /** 当前工作区根目录 */
  workspaceRoot: string | null
}

let _host: AxecoderHost | null = null

export const setAxecoderHost = (host: AxecoderHost | null) => {
  _host = host
}

export const getAxecoderHost = (): AxecoderHost => {
  if (!_host) throw new Error('AxecoderHost not initialized — call setAxecoderHost first')
  return _host
}

export const tryGetAxecoderHost = (): AxecoderHost | null => _host

export const CORE_VERSION = '0.9.4'
