import * as vscode from 'vscode'
import { setAxecoderHost, CORE_VERSION } from '@axecoder/core'
import { startBackgroundCodeGraphIndex } from '@axecoder/core/codegraph/manager'
import { createVscodeHost } from './host/vscode-host'
import { broadcastToWebviews, installCoreBroadcast } from './host/broadcast'
import {
  setExtensionContext,
  trackRecentProject,
} from './host/extension-context'
import { registerAgentCommands } from './agent-commands'
import { registerCompanionCommands } from './companion'
import { registerObservabilityCommands } from './observability'
import { registerWorkshopPanels } from './workshop-panels'
import { registerSettingsCommands } from './settings-panel'
import { registerAxecoderLanguageModelProvider } from './language-model-provider'
import { ChatWebviewProvider } from './webview/chat-provider'
import { startMetricsBroadcast } from './metrics-timer'
import { listModels } from '@axecoder/core/models-store'

let outputChannel: vscode.OutputChannel

export async function activate(context: vscode.ExtensionContext): Promise<void> {
  setExtensionContext(context)
  outputChannel = vscode.window.createOutputChannel('AxeCoder')
  context.subscriptions.push(outputChannel)

  installCoreBroadcast()
  const host = createVscodeHost(context, outputChannel)
  setAxecoderHost(host)

  outputChannel.appendLine(`AxeCoder extension activated (core ${CORE_VERSION})`)

  const chatProvider = new ChatWebviewProvider(context.extensionUri, context, outputChannel)
  context.subscriptions.push(
    vscode.window.registerWebviewViewProvider('axecoder.chat', chatProvider, {
      webviewOptions: { retainContextWhenHidden: true },
    }),
  )

  context.subscriptions.push(
    vscode.commands.registerCommand('axecoder.hello', () => {
      void vscode.window.showInformationMessage(`AxeCoder ${CORE_VERSION} — VS Code shell ready`)
    }),
  )

  registerAgentCommands(context, outputChannel)
  registerWorkshopPanels(context)
  registerObservabilityCommands(context)
  registerCompanionCommands(context)
  registerSettingsCommands(context)
  registerAxecoderLanguageModelProvider(context)
  startMetricsBroadcast(context)

  const openSettingsInChat = (tab: 'general' | 'models' | 'permissions' = 'general') => {
    broadcastToWebviews('settings:open', { tab })
    void vscode.commands.executeCommand('axecoder.chat.focus')
  }

  context.subscriptions.push(
    vscode.commands.registerCommand('axecoder.openSettingsInChat', () =>
      openSettingsInChat('general'),
    ),
    vscode.commands.registerCommand('axecoder.openModelsInChat', () =>
      openSettingsInChat('models'),
    ),
    vscode.commands.registerCommand('axecoder.openChat', () => {
      void vscode.commands.executeCommand('axecoder.chat.focus')
    }),
    vscode.commands.registerCommand('axecoder.toggleChat', () => {
      void vscode.commands.executeCommand('axecoder.chat.focus')
    }),
  )

  const modelsStatus = vscode.window.createStatusBarItem(vscode.StatusBarAlignment.Left, 200)
  modelsStatus.text = '$(gear) AxeCoder Models'
  modelsStatus.tooltip = '配置 API 模型（Cmd+Shift+,）'
  modelsStatus.command = 'axecoder.openModelsSettings'
  modelsStatus.backgroundColor = new vscode.ThemeColor('statusBarItem.warningBackground')
  modelsStatus.show()
  context.subscriptions.push(modelsStatus)

  const status = vscode.window.createStatusBarItem(vscode.StatusBarAlignment.Right, 100)
  status.text = '$(hubot) AxeCoder'
  status.tooltip = 'Open AxeCoder Chat'
  status.command = 'axecoder.openChat'
  status.show()
  context.subscriptions.push(status)

  const modelsStatusRight = vscode.window.createStatusBarItem(vscode.StatusBarAlignment.Right, 99)
  modelsStatusRight.text = '$(gear) Models'
  modelsStatusRight.tooltip = 'AxeCoder Models — Cmd+Shift+,'
  modelsStatusRight.command = 'axecoder.openModelsSettings'
  modelsStatusRight.show()
  context.subscriptions.push(modelsStatusRight)

  // 无模型时在编辑器区自动打开 Models 面板
  void listModels().then((data) => {
    const hasEnabled = data.models.some((m) => m.enabled)
    if (!hasEnabled) {
      void vscode.commands.executeCommand('axecoder.openModelsSettings')
    }
    if (!context.globalState.get<boolean>('axecoder.modelsHintShown')) {
      void context.globalState.update('axecoder.modelsHintShown', true)
      void vscode.window
        .showInformationMessage(
          'AxeCoder 模型配置不在 VS Code 自带齿轮里。请点左下角状态栏「AxeCoder Models」，或 Cmd+Shift+P → AxeCoder: Models。',
          '打开 Models',
        )
        .then((choice) => {
          if (choice === '打开 Models') {
            void vscode.commands.executeCommand('axecoder.openModelsSettings')
          }
        })
    }
  })

  const onWorkspaceReady = (folders: readonly vscode.WorkspaceFolder[] | undefined) => {
    const root = folders?.[0]?.uri.fsPath
    if (root) {
      void trackRecentProject(root)
      startBackgroundCodeGraphIndex(root)
    }
  }
  onWorkspaceReady(vscode.workspace.workspaceFolders)
  context.subscriptions.push(
    vscode.workspace.onDidChangeWorkspaceFolders(() =>
      onWorkspaceReady(vscode.workspace.workspaceFolders),
    ),
  )

  // 打开 AxeCoder 侧栏（非 Copilot CHAT）
  const focusAxecoderChat = () => {
    void vscode.commands.executeCommand('workbench.view.extension.axecoder')
    void vscode.commands.executeCommand('axecoder.chat.focus')
  }
  let chatFocused = false
  const tryFocusAxecoderChat = () => {
    if (chatFocused || !vscode.workspace.workspaceFolders?.length) return
    chatFocused = true
    focusAxecoderChat()
  }
  tryFocusAxecoderChat()
  context.subscriptions.push(
    vscode.workspace.onDidChangeWorkspaceFolders(tryFocusAxecoderChat),
  )
}

export function deactivate(): void {
  setAxecoderHost(null)
}

export const getOutputChannel = (): vscode.OutputChannel | undefined => outputChannel
