import * as vscode from 'vscode'
import { globalRpcBridge } from '../rpc/webview-bridge'
import { attachWebviewRpc, trackActiveEditor, webviewHtml } from './webview-utils'
import { getWorkspaceRoot } from '../host/broadcast'

/** Chat Webview — Legacy ChatPane via RPC shim */
export class ChatWebviewProvider implements vscode.WebviewViewProvider {
  private view?: vscode.WebviewView

  constructor(
    private readonly extensionUri: vscode.Uri,
    private readonly context: vscode.ExtensionContext,
    private readonly output: vscode.OutputChannel,
  ) {}

  resolveWebviewView(
    webviewView: vscode.WebviewView,
    _context: vscode.WebviewViewResolveContext,
    _token: vscode.CancellationToken,
  ): void {
    this.view = webviewView
    webviewView.webview.options = {
      enableScripts: true,
      localResourceRoots: [this.extensionUri],
    }
    webviewView.webview.html = webviewHtml(webviewView.webview, this.extensionUri, 'chat', 'AxeCoder Chat')
    attachWebviewRpc(webviewView.webview)
    trackActiveEditor(this.context, () => this.view?.webview)

    webviewView.webview.onDidReceiveMessage((msg: { type?: string }) => {
      if (msg.type === 'ready') {
        this.output.appendLine('[chat] webview ready')
        const root = getWorkspaceRoot()
        if (root) {
          globalRpcBridge.notifyActiveEditor(webviewView.webview, null)
        }
      }
    })
  }

  focusSession(_sessionId: string, _kind: 'agent' | 'workshop'): void {
    /* legacy sessions tree removed — use AgentsPanel in Chat webview */
  }
}
