export const permissionsWriteGlobalJson = async (jsonText: string) => {
  try {
    const parsed = JSON.parse(jsonText) as Partial<AppSettings>
    await setConfig(parsed)
    return { ok: true as const, data: await getConfig() }
  } catch (e) {
    return { ok: false as const, error: String(e) }
  }
}

