export const codeGraphStatus = async (projectRoot: string) => {
  const status = getCodeGraphPublicStatus(projectRoot)
  return {
    sqliteAvailable: status.sqliteAvailable,
    engineAvailable: status.engineAvailable,
    distPath: status.distPath,
    indexed: status.initialized,
    indexing: status.indexing,
  }
}

export const codeGraphIndex = async (projectRoot: string) => {
  if (!projectRoot.trim()) {
    return { ok: false as const, error: 'projectRoot is required' }
  }
  startBackgroundCodeGraphIndex(projectRoot)
  const res = await ensureCodeGraphSession(projectRoot)
  if (!res.ok) return res
  return { ok: true as const }
}

