import type * as vscode from 'vscode'
import { createRpcHandlers, type RpcHandler } from './registry'
import { registerWebviewPoster } from '../host/broadcast'
import { EVENT_CHANNELS, type EventListenerName } from './channels'

export type WebviewToExtension =
  | { type: 'rpc'; id: number; method: string; args: unknown[] }
  | { type: 'subscribe'; channels: string[] }
  | { type: 'ready'; panel?: string }

export type ExtensionToWebview =
  | { type: 'rpcResult'; id: number; result: unknown }
  | { type: 'rpcError'; id: number; error: string }
  | { type: 'event'; channel: string; payload: unknown }
  | { type: 'activeEditor'; path: string | null }
  | { type: 'sessionSelect'; sessionId: string; kind: 'agent' | 'workshop' }

const LISTENER_TO_CHANNEL: Record<EventListenerName, string> = EVENT_CHANNELS

let handlers: Record<string, RpcHandler> | null = null

const getHandlers = (): Record<string, RpcHandler> => {
  if (!handlers) handlers = createRpcHandlers()
  return handlers
}

export class WebviewRpcBridge {
  private readonly subs = new Map<string, Set<vscode.Webview>>()
  private disposePoster?: () => void

  constructor() {
    this.disposePoster = registerWebviewPoster((channel, payload) => {
      this.postEvent(channel, payload)
    })
  }

  attach(webview: vscode.Webview): void {
    webview.onDidReceiveMessage(async (msg: WebviewToExtension) => {
      if (msg.type === 'ready') return
      if (msg.type === 'subscribe') {
        for (const ch of msg.channels) {
          if (!this.subs.has(ch)) this.subs.set(ch, new Set())
          this.subs.get(ch)!.add(webview)
        }
        return
      }
      if (msg.type === 'rpc') {
        const map = getHandlers()
        const fn = map[msg.method]
        if (!fn) {
          void webview.postMessage({
            type: 'rpcError',
            id: msg.id,
            error: `Unknown RPC method: ${msg.method}`,
          } satisfies ExtensionToWebview)
          return
        }
        try {
          const result = await fn(...msg.args)
          void webview.postMessage({
            type: 'rpcResult',
            id: msg.id,
            result,
          } satisfies ExtensionToWebview)
        } catch (e) {
          void webview.postMessage({
            type: 'rpcError',
            id: msg.id,
            error: e instanceof Error ? e.message : String(e),
          } satisfies ExtensionToWebview)
        }
      }
    })
  }

  postEvent(channel: string, payload: unknown): void {
    const set = this.subs.get(channel)
    if (!set?.size) return
    const msg: ExtensionToWebview = { type: 'event', channel, payload }
    for (const wv of set) {
      void wv.postMessage(msg)
    }
  }

  notifyActiveEditor(webview: vscode.Webview, filePath: string | null): void {
    void webview.postMessage({ type: 'activeEditor', path: filePath } satisfies ExtensionToWebview)
  }

  notifySessionSelect(
    webview: vscode.Webview,
    sessionId: string,
    kind: 'agent' | 'workshop',
  ): void {
    void webview.postMessage({ type: 'sessionSelect', sessionId, kind } satisfies ExtensionToWebview)
  }

  static eventChannelsForListeners(names: EventListenerName[]): string[] {
    return names.map((n) => LISTENER_TO_CHANNEL[n])
  }

  dispose(): void {
    this.disposePoster?.()
    this.subs.clear()
  }
}

export const globalRpcBridge = new WebviewRpcBridge()
