import {
  deleteWorkshopSession,
  getWorkshopSession,
  listWorkshopSessions,
  newWorkshopSession,
  saveWorkshopSession,
} from '@axecoder/core/workshop/workshop-store'
import { sendWorkshopMessage } from '@axecoder/core/workshop/workshop-turn-orchestrator'
import { stopAgentTurn } from '@axecoder/core/agent/agent-loop'
import { listAgentSessions } from '@axecoder/core/agent/agent-session-store'
import type { ChatImageRef, WorkshopSession } from '@axecoder/core/models-types'

export const getWorkshopSessions = async (projectRoot: string) => ({
  sessions: await listWorkshopSessions(typeof projectRoot === 'string' ? projectRoot : ''),
})

export const getWorkshopSessionHandler = async (projectRoot: string, workshopId: string) =>
  getWorkshopSession(typeof projectRoot === 'string' ? projectRoot : '', workshopId)

export const saveWorkshopSessionHandler = async (
  projectRoot: string,
  session: WorkshopSession,
) => saveWorkshopSession(typeof projectRoot === 'string' ? projectRoot : '', session)

export const deleteWorkshopSessionHandler = async (projectRoot: string, workshopId: string) =>
  deleteWorkshopSession(typeof projectRoot === 'string' ? projectRoot : '', workshopId)

export const workshopStop = async (workshopId: string) => {
  const wid = typeof workshopId === 'string' ? workshopId.trim() : ''
  if (!wid) return { ok: false as const, error: 'Invalid workshop id' }
  const prefix = `workshop-${wid}-`
  let stopped = 0
  for (const { id } of listAgentSessions()) {
    if (id.startsWith(prefix)) {
      stopAgentTurn(id)
      stopped++
    }
  }
  return { ok: true as const, stopped }
}

export const workshopStartRun = async (
  projectRoot: string,
  workshopId: string,
  userBrief: string,
  modelId: string,
) => {
  let session: WorkshopSession | null = null
  if (workshopId?.trim()) {
    const got = await getWorkshopSession(projectRoot, workshopId)
    session = got.session
  }
  if (!session) {
    session = newWorkshopSession(projectRoot, userBrief, modelId, workshopId)
  }
  return sendWorkshopMessage(projectRoot, session, userBrief, modelId)
}

export const workshopSendMessage = async (
  projectRoot: string,
  workshopId: string,
  text: string,
  modelId: string,
  _mode?: unknown,
  displayText?: string,
  imageRefs?: ChatImageRef[],
  preferredAssigneeUserId?: string,
  orchestrationChatMode?: string,
) => {
  const got = await getWorkshopSession(projectRoot, workshopId)
  let session = got.session
  if (!session) {
    session = newWorkshopSession(projectRoot, text, modelId, workshopId)
  }
  return sendWorkshopMessage(
    projectRoot,
    session,
    text,
    modelId,
    displayText,
    imageRefs,
    preferredAssigneeUserId,
    orchestrationChatMode,
  )
}

export const workshopSendUserAnswer = async (
  projectRoot: string,
  workshopId: string,
  answer: string,
) => {
  const got = await getWorkshopSession(projectRoot, workshopId)
  const session = got.session
  if (!session) return { ok: false as const, error: 'Workshop not found' }
  return sendWorkshopMessage(projectRoot, session, answer, session.modelId ?? '')
}
