import type * as vscode from 'vscode'
import { broadcastToWebviews } from './host/broadcast'
import { getAiMetricsSnapshot } from '@axecoder/core/ai-metrics-store'

let timer: ReturnType<typeof setInterval> | null = null

export const startMetricsBroadcast = (context: vscode.ExtensionContext): void => {
  if (timer) return
  timer = setInterval(() => {
    broadcastToWebviews('aiMetrics:update', getAiMetricsSnapshot())
  }, 1500)
  context.subscriptions.push({
    dispose: () => {
      if (timer) {
        clearInterval(timer)
        timer = null
      }
    },
  })
}
