import * as vscode from 'vscode'
import { setRendererBroadcastImpl } from '@axecoder/core/renderer-broadcast'

type WebviewPoster = (channel: string, payload: unknown) => void

const posters = new Set<WebviewPoster>()

export const registerWebviewPoster = (fn: WebviewPoster): (() => void) => {
  posters.add(fn)
  return () => posters.delete(fn)
}

export const broadcastToWebviews = (channel: string, payload: unknown): void => {
  for (const post of posters) {
    try {
      post(channel, payload)
    } catch {
      /* disposed */
    }
  }
}

export const installCoreBroadcast = (): void => {
  setRendererBroadcastImpl((channel, payload) => {
    broadcastToWebviews(channel, payload)
  })
}

export const getWorkspaceRoot = (): string | null =>
  vscode.workspace.workspaceFolders?.[0]?.uri.fsPath ?? null

export const onWorkspaceRootChange = (
  listener: (root: string | null) => void,
): vscode.Disposable => {
  listener(getWorkspaceRoot())
  return vscode.workspace.onDidChangeWorkspaceFolders(() => listener(getWorkspaceRoot()))
}
