import { getAiMetricsSnapshot } from '@axecoder/core/ai-metrics-store'

export const getAiMetricsSnapshotHandler = async (
  filter?: string | import('@axecoder/core/models-types').AiMetricsFilter,
) => {
  if (typeof filter === 'string') {
    const id = filter.trim()
    return getAiMetricsSnapshot(id || undefined)
  }
  if (filter && typeof filter === 'object') return getAiMetricsSnapshot(filter)
  return getAiMetricsSnapshot()
}
