import * as vscode from 'vscode'
import { attachWebviewRpc, webviewHtml } from './webview/webview-utils'

const openPanel = (
  context: vscode.ExtensionContext,
  command: string,
  bundle: string,
  title: string,
  column: vscode.ViewColumn = vscode.ViewColumn.Beside,
): void => {
  context.subscriptions.push(
    vscode.commands.registerCommand(command, () => {
      const panel = vscode.window.createWebviewPanel(command, title, column, {
        enableScripts: true,
        retainContextWhenHidden: true,
        localResourceRoots: [context.extensionUri],
      })
      panel.webview.html = webviewHtml(panel.webview, context.extensionUri, bundle, title)
      attachWebviewRpc(panel.webview)
    }),
  )
}

export const registerObservabilityCommands = (context: vscode.ExtensionContext): void => {
  openPanel(context, 'axecoder.openMetrics', 'metrics', 'AxeCoder AI Performance')
  openPanel(context, 'axecoder.openTrace', 'trace', 'AxeCoder AI Request Trace')
}
