import { spawn } from 'node:child_process'
import path from 'node:path'
import * as vscode from 'vscode'
import { logOutput } from '@axecoder/core/output-channel'

export const runGit = (cwd: string, args: string[]): Promise<string> =>
  new Promise((resolve, reject) => {
    const proc = spawn('git', args, { cwd, env: process.env })
    let out = ''
    let err = ''
    proc.stdout?.on('data', (d) => {
      out += d.toString()
    })
    proc.stderr?.on('data', (d) => {
      err += d.toString()
    })
    proc.on('close', (code) => {
      if (code === 0) resolve(out.trim())
      else reject(new Error(err.trim() || `git exit ${code}`))
    })
    proc.on('error', () => reject(new Error('Git not installed or not executable')))
  })

const resolveGitPath = (cwd: string, file: string) => {
  const f = file.trim()
  if (!f) throw new Error('Missing file path')
  return path.isAbsolute(f) ? f : path.join(cwd, f)
}

export const gitStatus = async (cwd: string) => {
  if (!cwd) return { ok: false as const, error: 'No project open' }
  try {
    const branch = await runGit(cwd, ['rev-parse', '--abbrev-ref', 'HEAD'])
    const raw = await runGit(cwd, ['status', '--porcelain'])
    const changes = raw
      ? raw.split('\n').filter(Boolean).map((line) => {
          const code = line.slice(0, 2)
          const file = line.slice(3).trim()
          return { code, file }
        })
      : []
    return { ok: true as const, branch, changes }
  } catch (e) {
    return { ok: false as const, error: e instanceof Error ? e.message : 'Git unavailable' }
  }
}

export const gitStage = async (cwd: string, file: string) => {
  if (!cwd) return { ok: false as const, error: 'No project open' }
  try {
    const p = resolveGitPath(cwd, file)
    await runGit(cwd, ['add', '--', p])
    logOutput('Git', `Staged ${file}`)
    return { ok: true as const }
  } catch (e) {
    return { ok: false as const, error: e instanceof Error ? e.message : 'Stage failed' }
  }
}

export const gitUnstage = async (cwd: string, file: string) => {
  if (!cwd) return { ok: false as const, error: 'No project open' }
  try {
    const p = resolveGitPath(cwd, file)
    await runGit(cwd, ['reset', 'HEAD', '--', p])
    logOutput('Git', `Unstaged ${file}`)
    return { ok: true as const }
  } catch (e) {
    return { ok: false as const, error: e instanceof Error ? e.message : 'Unstage failed' }
  }
}

export const gitStageAll = async (cwd: string) => {
  if (!cwd) return { ok: false as const, error: 'No project open' }
  try {
    await runGit(cwd, ['add', '-A'])
    logOutput('Git', 'Staged all changes')
    return { ok: true as const }
  } catch (e) {
    return { ok: false as const, error: e instanceof Error ? e.message : 'Stage all failed' }
  }
}

export const gitCommit = async (cwd: string, message: string, amend?: boolean) => {
  if (!cwd) return { ok: false as const, error: 'No project open' }
  try {
    const args = amend ? ['commit', '--amend', '-m', message] : ['commit', '-m', message]
    await runGit(cwd, args)
    logOutput('Git', amend ? 'Amended commit' : `Committed: ${message}`)
    return { ok: true as const }
  } catch (e) {
    return { ok: false as const, error: e instanceof Error ? e.message : 'Commit failed' }
  }
}

export const gitDiff = async (cwd: string, staged?: boolean) => {
  if (!cwd) return { ok: false as const, error: 'No project open' }
  try {
    const args = staged ? ['diff', '--cached'] : ['diff']
    const text = await runGit(cwd, args)
    return { ok: true as const, text }
  } catch (e) {
    return { ok: false as const, error: e instanceof Error ? e.message : 'Diff failed' }
  }
}

export const gitShow = async (cwd: string, file: string, staged?: boolean) => {
  if (!cwd) return { ok: false as const, error: 'No project open' }
  try {
    const p = resolveGitPath(cwd, file)
    const args = staged ? ['show', `:${p}`] : ['show', `HEAD:${p}`]
    const text = await runGit(cwd, args)
    return { ok: true as const, text }
  } catch (e) {
    return { ok: false as const, error: e instanceof Error ? e.message : 'Show failed' }
  }
}

export const gitForgeStatus = async (cwd: string) => {
  const { buildGitForgeContext } = await import('@axecoder/core/git-forge/detect-forge')
  try {
    const ctx = await buildGitForgeContext(cwd)
    return { ok: true as const, ...ctx }
  } catch (e) {
    return { ok: false as const, error: e instanceof Error ? e.message : String(e) }
  }
}

export const gitOpenUrl = async (url: string) => {
  await vscode.env.openExternal(vscode.Uri.parse(url))
  return { ok: true as const }
}

