import { listAllSessions as coreListAll } from '@axecoder/core/session/session-registry'
import { suggestChatSessionTitle } from '@axecoder/core/session/session-title'

export const listAllSessions = async (projectRoot: string) =>
  coreListAll(typeof projectRoot === 'string' ? projectRoot : '')

export const suggestTitle = async (
  modelId: string,
  messages: { role: 'user' | 'assistant'; text: string }[],
  currentTitle: string,
) => {
  const list = Array.isArray(messages) ? messages : []
  const normalized = list
    .filter(
      (m) =>
        m &&
        (m.role === 'user' || m.role === 'assistant') &&
        typeof m.text === 'string',
    )
    .map((m) => ({ role: m.role, text: m.text }))
  return suggestChatSessionTitle(
    typeof modelId === 'string' ? modelId : '',
    normalized,
    typeof currentTitle === 'string' ? currentTitle : '',
  )
}
