/** LSP 编辑器通知 — 与 Electron IPC 解耦，供 agent tool-executor 使用 */

type NotifyWin = (() => { webContents: { send: (ch: string, payload: unknown) => void } } | null) | null

let notifyWin: NotifyWin = null

export const setLspEditorNotifyWin = (getWin: NotifyWin) => {
  notifyWin = getWin
}

export const notifyLspFileRefresh = (filePath: string) => {
  notifyWin?.()?.webContents.send('lsp:refreshFile', { file: filePath })
}

export const resetLspEditorState = () => {
  notifyWin = null
}
