import * as vscode from 'vscode'
import * as path from 'node:path'
import * as fs from 'node:fs'
import { globalRpcBridge } from '../rpc/webview-bridge'

const distDir = (extensionUri: vscode.Uri) =>
  path.join(extensionUri.fsPath, 'webview', 'dist')

const rewriteAssetUrls = (
  webview: vscode.Webview,
  html: string,
  baseDir: string,
): string =>
  html.replace(/(?:src|href)="\/([^"]+)"/g, (match, assetPath: string) => {
    const file = path.join(baseDir, assetPath)
    if (!fs.existsSync(file)) return match
    const uri = webview.asWebviewUri(vscode.Uri.file(file))
    const attr = match.startsWith('src=') ? 'src' : 'href'
    return `${attr}="${uri}"`
  })

export const bundleUri = (
  extensionUri: vscode.Uri,
  bundleName: string,
): vscode.Uri | null => {
  const file = path.join(distDir(extensionUri), `${bundleName}.js`)
  if (!fs.existsSync(file)) return null
  return vscode.Uri.file(file)
}

export const webviewHtml = (
  webview: vscode.Webview,
  extensionUri: vscode.Uri,
  bundleName: string,
  title: string,
): string => {
  const base = distDir(extensionUri)
  const htmlFile = path.join(base, `${bundleName}.html`)
  if (fs.existsSync(htmlFile)) {
    const raw = fs.readFileSync(htmlFile, 'utf8')
    const withCsp = raw.replace(
      '<head>',
      `<head><meta http-equiv="Content-Security-Policy" content="default-src 'none'; img-src ${webview.cspSource} https: data:; font-src ${webview.cspSource}; style-src ${webview.cspSource} 'unsafe-inline'; script-src ${webview.cspSource};">`,
    )
    return rewriteAssetUrls(webview, withCsp, base)
  }

  const scriptUri = bundleUri(extensionUri, bundleName)
  if (scriptUri) {
    const src = webview.asWebviewUri(scriptUri)
    return `<!DOCTYPE html><html><head><meta charset="UTF-8"><title>${title}</title></head><body style="margin:0;padding:0;height:100vh;overflow:hidden"><div id="app"></div><script src="${src}"></script></body></html>`
  }
  return `<!DOCTYPE html><html><body style="font-family:var(--vscode-font-family);padding:16px"><h3>${title}</h3><p>Run <code>npm run compile --prefix extensions/axecoder</code> to build webview bundles.</p></body></html>`
}

export const attachWebviewRpc = (webview: vscode.Webview): void => {
  globalRpcBridge.attach(webview)
}

export const trackActiveEditor = (
  context: vscode.ExtensionContext,
  getWebview: () => vscode.Webview | undefined,
): void => {
  const push = () => {
    const wv = getWebview()
    if (!wv) return
    const ed = vscode.window.activeTextEditor
    globalRpcBridge.notifyActiveEditor(wv, ed?.document.uri.fsPath ?? null)
  }
  context.subscriptions.push(vscode.window.onDidChangeActiveTextEditor(() => push()))
  push()
}
