import {
  deleteChatSession,
  getChatSession,
  listChatSessions,
  saveChatSession,
} from '@axecoder/core/chat-store'
import {
  forkChatBranch,
  formatBranchTree,
  listChatBranches,
  parseBranchArgs,
  messageIndexAtUserTurn,
  resolveBranchRef,
} from '@axecoder/core/chat-branch'
import {
  chatImageRefPreviewDataUrl,
  resolveChatImageRefs,
  saveChatPastedImage,
} from '@axecoder/core/chat-attachments'
import { chatWithToolsForModel } from '@axecoder/core/ai/chat-with-tools'
import type { AiChatMessage, ChatImageRef, ChatSession } from '@axecoder/core/models-types'

export const getChatSessionsHandler = async (projectRoot: string) => ({
  sessions: await listChatSessions(typeof projectRoot === 'string' ? projectRoot : ''),
})

export const getChatSessionHandler = async (projectRoot: string, sessionId: string) => ({
  session: await getChatSession(
    typeof projectRoot === 'string' ? projectRoot : '',
    sessionId,
  ),
})

export const saveChatSessionHandler = async (projectRoot: string, session: ChatSession) =>
  saveChatSession(typeof projectRoot === 'string' ? projectRoot : '', session)

export const deleteChatSessionHandler = async (projectRoot: string, sessionId: string) =>
  deleteChatSession(typeof projectRoot === 'string' ? projectRoot : '', sessionId)

export const chatBranchTree = async (projectRoot: string, currentId?: string) => {
  const listed = await listChatBranches(projectRoot)
  if (!listed.ok) return listed
  return { ok: true as const, text: formatBranchTree(listed.branches, currentId) }
}

export const chatForkBranch = async (
  projectRoot: string,
  sourceSessionId: string,
  args?: string,
) => {
  const parsed = parseBranchArgs(args ?? '')
  const { session: source } = await getChatSession(projectRoot, sourceSessionId)
  if (!source) return { ok: false as const, error: 'Session not found' }
  let forkMessageIndex: number | undefined
  if (parsed.fromTurn) {
    forkMessageIndex = messageIndexAtUserTurn(source.messages, parsed.turn)
  }
  return forkChatBranch(projectRoot, sourceSessionId, {
    forkMessageIndex,
    name: parsed.name || undefined,
  })
}

export const chatSwitchBranch = async (
  projectRoot: string,
  ref: string,
  currentId?: string,
) => {
  const listed = await listChatBranches(projectRoot)
  if (!listed.ok) return listed
  const match = resolveBranchRef(listed.branches, ref)
  if (!match) return { ok: false as const, error: `Branch not found: ${ref}` }
  const { session } = await getChatSession(projectRoot, match.id)
  if (!session) return { ok: false as const, error: 'Branch session missing on disk' }
  return {
    ok: true as const,
    session,
    tree: formatBranchTree(listed.branches, currentId === match.id ? match.id : match.id),
  }
}

export const saveChatPastedImageHandler = async (
  sessionId: string,
  base64: string,
  mimeType: string,
) => saveChatPastedImage(sessionId, base64, mimeType)

export const resolveChatImageRefsHandler = async (refs: ChatImageRef[]) =>
  resolveChatImageRefs(refs)

export const getChatImagePreview = async (ref: ChatImageRef) =>
  chatImageRefPreviewDataUrl(ref)

export const aiChat = async (
  modelId: string,
  messages: AiChatMessage[],
  streamId?: string,
  reasoningEffort?: string,
) => chatWithToolsForModel(modelId, messages, streamId, reasoningEffort)
