import * as vscode from 'vscode'
import type { SettingsTabId } from '../../../src/components/workbench/SettingsPanel.vue'
import { attachWebviewRpc, webviewHtml } from './webview/webview-utils'

const openSettingsPanel = (
  context: vscode.ExtensionContext,
  tab: SettingsTabId,
  title: string,
): void => {
  const panel = vscode.window.createWebviewPanel(
    tab === 'models' ? 'axecoder.models' : 'axecoder.settings',
    title,
    vscode.ViewColumn.One,
    {
      enableScripts: true,
      retainContextWhenHidden: true,
      localResourceRoots: [context.extensionUri],
    },
  )
  const html = webviewHtml(panel.webview, context.extensionUri, 'settings', title).replace(
    '<body',
    `<body data-settings-tab="${tab}"`,
  )
  panel.webview.html = html
  attachWebviewRpc(panel.webview)
  panel.webview.onDidReceiveMessage((msg: { type?: string }) => {
    if (msg?.type === 'closeSettingsPanel') {
      panel.dispose()
    }
  })
  panel.reveal(vscode.ViewColumn.One)
}

/** 在编辑器区域打开 Settings（与 master 弹窗同级可见性，不再依赖侧栏 webview） */
export const registerSettingsCommands = (context: vscode.ExtensionContext): void => {
  context.subscriptions.push(
    vscode.commands.registerCommand('axecoder.openSettings', () => {
      openSettingsPanel(context, 'general', 'AxeCoder Settings')
    }),
    vscode.commands.registerCommand('axecoder.openModelsSettings', () => {
      openSettingsPanel(context, 'models', 'AxeCoder Models')
    }),
  )
}
