import {
  deleteModel,
  listModels,
  saveModel,
  setActiveModel,
  toggleModel,
} from '@axecoder/core/models-store'
import { pingModel } from '@axecoder/core/models-ping'
import { listAllProviderCapabilities } from '@axecoder/core/models-types'
import type { ModelSaveInput } from '@axecoder/core/models-types'

export const listModelsHandler = async () => listModels()

export const saveModelHandler = async (input: ModelSaveInput) => saveModel(input)

export const deleteModelHandler = async (id: string) => deleteModel(id)

export const toggleModelHandler = async (id: string, enabled: boolean) => toggleModel(id, enabled)

export const setActiveModelHandler = async (id: string) => setActiveModel(id)

export const pingModelHandler = async (id: string) => pingModel(id)

export const getProviderCapabilities = async () => listAllProviderCapabilities()
