/** VS Code 扩展 CJS bundle 内安全解析 rg 二进制路径（替代 @vscode/ripgrep ESM） */
import { createRequire } from 'node:module'
import path from 'node:path'

const appRoot =
  process.env.APP_ROOT ??
  path.resolve(typeof __dirname !== 'undefined' ? __dirname : '.', '..', '..', '..')
const extMain = path.join(appRoot, 'extensions/axecoder/out/extension.js')
const req = createRequire(extMain)

const arch = process.env.npm_config_arch || process.arch
const binaryName = process.platform === 'win32' ? 'rg.exe' : 'rg'
const platformPkg = `@vscode/ripgrep-${process.platform}-${arch}`

let rgPath: string
try {
  rgPath = req.resolve(`${platformPkg}/bin/${binaryName}`)
} catch {
  throw new Error(
    `Could not find ${platformPkg}. Run npm install in the AxeCoder repo root.`,
  )
}

export { rgPath }
