/** 向渲染进程广播 — Electron 环境可用；VS Code / vitest 下为 no-op */
let broadcastImpl: ((channel: string, payload: unknown) => void) | null = null

export const setRendererBroadcastImpl = (
  fn: ((channel: string, payload: unknown) => void) | null,
) => {
  broadcastImpl = fn
}

export const broadcastToRenderers = (channel: string, payload: unknown) => {
  if (broadcastImpl) {
    broadcastImpl(channel, payload)
    return
  }
  try {
    // 动态加载，避免 core 在 VS Code Extension Host 中硬依赖 electron
    // eslint-disable-next-line @typescript-eslint/no-require-imports
    const { BrowserWindow } = require('electron') as typeof import('electron')
    if (!BrowserWindow?.getAllWindows) return
    for (const w of BrowserWindow.getAllWindows()) {
      if (w.isDestroyed()) continue
      w.webContents.send(channel, payload)
    }
  } catch {
    /* vitest / vscode extension host */
  }
}
