export const agentSend = async (
  projectRoot: string,
  modelId: string,
  messages: AiChatMessage[],
  chatMode?: string,
  assigneeUserId?: string,
  roleWorkflowInvoke?: boolean,
  reasoningEffort?: string,
  clientChatId?: string,
) => {
  const history = (Array.isArray(messages) ? messages : [])
    .filter((m) => m.role === 'user' || m.role === 'assistant')
    .map((m) => ({
      role: m.role as 'user' | 'assistant',
      content: typeof m.content === 'string' ? m.content : '',
      ...(m.role === 'user' && m.images?.length ? { images: m.images } : {}),
      ...(m.role === 'assistant' && m.reasoningContent
        ? { reasoningContent: m.reasoningContent }
        : {}),
    }))
  if (!history.some((m) => m.role === 'user')) {
    return { ok: false as const, error: 'No user message' }
  }
  return startAgentTurn(
    projectRoot,
    modelId,
    history,
    chatMode,
    assigneeUserId,
    roleWorkflowInvoke === true,
    reasoningEffort,
    clientChatId,
  )
}

