export const agentListMcp = async (projectRoot?: string) => {
  try {
    const text = await listMcpResources(projectRoot)
    return { ok: true as const, text: typeof text === 'string' ? text : JSON.stringify(text) }
  } catch (e) {
    return { ok: false as const, error: String(e) }
  }
}

