export const agentListOutputStyles = async (projectRoot?: string) => {
  try {
    await refreshCustomOutputStylesCache(projectRoot)
    const custom = getCachedCustomOutputStyles()
    const styles = [
      ...Object.entries(OUTPUT_STYLE_CONFIG).map(([id, cfg]) => ({
        id,
        name: cfg.name,
        description: cfg.description,
        source: 'builtin',
      })),
      ...custom.map((s) => ({
        id: s.id,
        name: s.name,
        description: s.description,
        source: s.source,
      })),
    ]
    const cfg = await getConfig()
    return {
      ok: true as const,
      activeId: cfg.agentOutputStyle ?? DEFAULT_OUTPUT_STYLE_NAME,
      styles,
      dirs: [],
    }
  } catch (e) {
    return { ok: false as const, error: String(e) }
  }
}

