export const agentProjectMemory = async (projectRoot: string) => {
  if (!projectRoot?.trim()) return { ok: false as const, error: 'No project' }
  const { composeMemoryPrompt, loadMemoryIndex } = await import('@axecoder/core/agent/agent-memory')
  const index = await loadMemoryIndex(projectRoot)
  const full = await composeMemoryPrompt(projectRoot)
  const text =
    full?.trim() ||
    (index ? `# Saved memories\n\n${index}` : '(no project memory yet — use Remember tool or create AGENTS.md)')
  return { ok: true as const, text }
}

